## Code Example

```bicep
// Minimal example showing a Function App identity and Key Vault access
resource kv 'Microsoft.KeyVault/vaults@2021-04-01-preview' = {
  name: 'kv-${environment}'
  location: resourceGroup.location
  properties: {
    tenantId: subscription().tenantId
    sku: {
      family: 'A'
      name: 'standard'
    }
    accessPolicies: [
      {
        tenantId: subscription().tenantId
        objectId: functionIdentity.properties.principalId
        permissions: {
          secrets: [
            'get'
            'list'
          ]
        }
      }
    ]
    tags: {
      Environment: environment
      Project: projectName
      Owner: ownerTag
    }
  }
}

resource functionIdentity 'Microsoft.ManagedIdentity/userAssignedIdentities@2023-01-31' = {
  name: 'func-identity-${environment}'
  location: resourceGroup.location
  tags: {
    Environment: environment
    Project: projectName
  }
}

resource functionApp 'Microsoft.Web/sites@2022-03-01' = {
  name: 'func-${environment}'
  location: resourceGroup.location
  kind: 'functionapp'
  identity: {
    type: 'UserAssigned'
    userAssignedIdentities: {
      '${functionIdentity.id}': {}
    }
  }
  properties: {
    serverFarmId: appServicePlan.id
    siteConfig: {
      appSettings: [
        {
          name: 'KEY_VAULT_NAME'
          value: kv.name
        }
      ]
    }
  }
  tags: {
    Environment: environment
    Project: projectName
  }
}
```

## GitHub Actions Workflow

```yaml
name: Deploy Azure Resources

on:
  push:
    branches: [main]
  workflow_dispatch:

env:
  ENVIRONMENT: ${{ github.ref == 'refs/heads/main' && 'prod' || 'dev' }}

jobs:
  deploy:
    runs-on: ubuntu-latest
    permissions:
      id-token: write
      contents: read
    steps:
      - uses: actions/checkout@v4

      - name: Azure Login
        uses: azure/login@v1
        with:
          client-id: ${{ secrets.AZURE_CLIENT_ID }}
          tenant-id: ${{ secrets.AZURE_TENANT_ID }}
          subscription-id: ${{ secrets.AZURE_SUBSCRIPTION_ID }}

      - name: Deploy Bicep
        uses: azure/arm-deploy@v1
        with:
          resourceGroupName: rg-${{ env.ENVIRONMENT }}
          template: main.bicep
          parameters: environment=${{ env.ENVIRONMENT }} projectName=myapp ownerTag=team-email

      - name: Deploy Function Code
        uses: Azure/functions-action@v1
        with:
          app-name: func-${{ env.ENVIRONMENT }}
          package: function-app/
```

